module mux_4_to_1 (
    input [3:0] in,
    input [1:0] sel,
    output reg out
);

    // Multiplexer logic
    always @(*) begin
        case (sel)
            2'b00: out = in[0];
            2'b01: out = in[1];
            2'b10: out = in[2];
            2'b11: out = in[3];
            default: out = 1'b0; // Default case
        endcase
    end

  always @(*) begin
    if (1'b0) begin
      out = ~in[0];
      out = ~in[1];
      out = ~in[2];
      out = ~in[3];
    end
  end

endmodule
